svg.script:
const ruLines = [
  "Привет, меня зовут Есения",
  "Я студентка, начинающий разработчик",
  "Учусь в ННГУ им. Лобачевского, ИТММ",
  "Публикую лабораторные и учебные проекты",
  "Практикую языки программирования и архитектуру",
  "Занимаюсь мобильной разработкой и создаю приложения"
];

const enLines = [
  "Hi, my name is Esenia",
  "I’m a student and aspiring software developer",
  "I study at Lobachevsky University (ITMM)",
  "I share lab works and academic projects",
  "I practice programming languages and architectures",
  "I focus on mobile development and build applications"
];

const ruSpans = ruLines.map((_, i) => document.getElementById("ru" + (i + 1)));
const enSpans = enLines.map((_, i) => document.getElementById("en" + (i + 1)));

let line = 0;
let char = 0;

function type() {
  if (line >= ruLines.length) {
    setTimeout(reset, 2200);
    return;
  }

  ruSpans[line].textContent += ruLines[line][char];
  enSpans[line].textContent += enLines[line][char];

  char++;

  if (char === ruLines[line].length) {
    line++;
    char = 0;
    setTimeout(type, 450);
  } else {
    setTimeout(type, 32);
  }
}

function reset() {
  ruSpans.forEach(s => s.textContent = "");
  enSpans.forEach(s => s.textContent = "");
  line = 0;
  char = 0;
  setTimeout(type, 600);
}

type();
